SELECT order_id,count(item_id) as orderGoodCount,sum(sorting_status) as orderGoodSortCount FROM store_goods_order_item where order_id in
#{orderId}
GROUP BY order_id

select  sgo.*,
    sgoi.item_id,sgoi.goods_id,sgoi.spu_no,sgoi.quantity,sgoi.amount,sgoi.price as sgoi_price,sgoi.discount,sgoi.sorting_price as sgoi_sorting_price,sgoi.comment as sgoi_comment,
    sgoi.create_time as sgoi_create_time,sgoi.unit_id,sgoi.print_status as sgoi_print_status,sgoi.sorting_status,sgoi.last_modify_time as sgoi_last_modify_time,
    sgqg.property_name as good_name,
    sgs.image as goods_img,
    sgsu.name as unit_name,
    ssd.sorting_weight,ssd.sorting_quantity,ssd.sorting_quantity_unit
from store_goods_order sgo
left join store_goods_order_item sgoi on sgo.order_id = sgoi.order_id
left join store_goods_quotation_goods sgqg on sgoi.goods_id = sgqg.goods_id
left join store_goods_spu sgs on sgoi.spu_no = sgs.spu_no
left join store_goods_sales_unit sgsu on sgoi.unit_id = sgsu.unit_id
left join store_sorting_detail ssd on sgoi.item_id = ssd.order_item_id  and ssd.status = '1'

